3.class #=> Fixnum

3.to_s #=> "3"


# Um pouco de aritmética básica

1 + 1 #=> 2
8 - 1 #=> 7
10 * 2 #=> 20
35 / 5 #=> 7

# Aritmética é apenas açúcar sintático
# para chamar um método de um objeto
1.+(3) #=> 4
10.* 5 #=> 50

# Valores especiais são objetos
nil # Nada para ver aqui
true # verdadeiro
false # falso

nil.class #=> NilClass
