## 6. 模組
####################################################

# 你可以引入模組來做使用
import math
print math.sqrt(16)  # => 4
                     # math.sqrt()為取根號

# 你可以只從模組取出特定幾個函式
from math import ceil, floor
print ceil(3.7)  # => 4.0
print floor(3.7)   # => 3.0

# 你可以將所有的函式從模組中引入
# 注意：不建議這麼做
from math import *

# 你可以用 as 簡寫模組名稱
import math as m
math.sqrt(16) == m.sqrt(16)   # => True
# 你也可以測試函示是否相等
from math import sqrt
math.sqrt == m.sqrt == sqrt  # => True

# Python的模組就只是一般的Python檔。
# 你可以自己的模組自己寫、自己的模組自己引入
# 模組的名稱和檔案名稱一樣

# 你可以用dir()來查看有哪些可用函式和屬性
import math
dir(math)


